/// Executor for FileUpload flow
pub struct FileUploadFlowExecutor<H: FileUploadStepHandler>(FlowExecutor<H>);

impl<H: FileUploadStepHandler + Send + Sync + 'static> FileUploadFlowExecutor<H> {
    /// Create a new flow executor
    pub fn new(handler: Arc<H>) -> Self {
        Self(FlowExecutor::new(handler))
    }

    /// Start a new flow instance
    pub fn start(&self, instance_id: impl Into<String>) -> FileUploadFlowInstance {
        self.0.start(instance_id, FileUploadFlowStep::LoadBucket)
    }

    /// Execute the current step
    pub async fn execute_step(&self, instance: &mut FileUploadFlowInstance) -> Result<(), FlowError> {
        let current_step = match instance.current_step {
            Some(step) => step,
            None => return Err(FlowError::NoCurrentStep),
        };

        let next_step = match current_step {
            FileUploadFlowStep::LoadBucket => {
                self.0.handler.handle_load_bucket(instance).await?
            }
            FileUploadFlowStep::CheckBucketActive => {
                let next = self.0.handler.evaluate_check_bucket_active(instance).await?;
                Some(next)
            }
            FileUploadFlowStep::CheckDeduplicationEnabled => {
                let next = self.0.handler.evaluate_check_deduplication_enabled(instance).await?;
                Some(next)
            }
            FileUploadFlowStep::CalculateChecksum => {
                self.0.handler.handle_calculate_checksum(instance).await?
            }
            FileUploadFlowStep::CheckDuplicateContent => {
                self.0.handler.handle_check_duplicate_content(instance).await?
            }
            FileUploadFlowStep::UseExistingContent => {
                self.0.handler.handle_use_existing_content(instance).await?
            }
            FileUploadFlowStep::DetectMimeType => {
                self.0.handler.handle_detect_mime_type(instance).await?
            }
            FileUploadFlowStep::ValidateFileType => {
                let next = self.0.handler.evaluate_validate_file_type(instance).await?;
                Some(next)
            }
            FileUploadFlowStep::ValidateFileSize => {
                let next = self.0.handler.evaluate_validate_file_size(instance).await?;
                Some(next)
            }
            FileUploadFlowStep::LoadQuota => {
                self.0.handler.handle_load_quota(instance).await?
            }
            FileUploadFlowStep::CreateDefaultQuota => {
                self.0.handler.handle_create_default_quota(instance).await?
            }
            FileUploadFlowStep::CheckQuota => {
                let next = self.0.handler.evaluate_check_quota(instance).await?;
                Some(next)
            }
            FileUploadFlowStep::CreateFileRecord => {
                self.0.handler.handle_create_file_record(instance).await?
            }
            FileUploadFlowStep::CheckShouldStoreContent => {
                let next = self.0.handler.evaluate_check_should_store_content(instance).await?;
                Some(next)
            }
            FileUploadFlowStep::StoreContent => {
                self.0.handler.handle_store_content(instance).await?
            }
            FileUploadFlowStep::CreateContentHash => {
                self.0.handler.handle_create_content_hash(instance).await?
            }
            FileUploadFlowStep::LinkContentHash => {
                self.0.handler.handle_link_content_hash(instance).await?
            }
            FileUploadFlowStep::UpdateFileProcessing => {
                self.0.handler.handle_update_file_processing(instance).await?
            }
            FileUploadFlowStep::ScanFile => {
                self.0.handler.handle_scan_file(instance).await?
            }
            FileUploadFlowStep::CheckScanResult => {
                let next = self.0.handler.evaluate_check_scan_result(instance).await?;
                Some(next)
            }
            FileUploadFlowStep::UpdateScanComplete => {
                self.0.handler.handle_update_scan_complete(instance).await?
            }
            FileUploadFlowStep::GenerateMediaThumbnails => {
                let next = self.0.handler.evaluate_generate_media_thumbnails(instance).await?;
                Some(next)
            }
            FileUploadFlowStep::CreateImageThumbnail => {
                self.0.handler.handle_create_image_thumbnail(instance).await?
            }
            FileUploadFlowStep::CreateVideoThumbnail => {
                self.0.handler.handle_create_video_thumbnail(instance).await?
            }
            FileUploadFlowStep::CreateDocumentPreview => {
                self.0.handler.handle_create_document_preview(instance).await?
            }
            FileUploadFlowStep::CheckCdnEnabled => {
                let next = self.0.handler.evaluate_check_cdn_enabled(instance).await?;
                Some(next)
            }
            FileUploadFlowStep::GenerateCdnUrl => {
                self.0.handler.handle_generate_cdn_url(instance).await?
            }
            FileUploadFlowStep::UpdateCdnInfo => {
                self.0.handler.handle_update_cdn_info(instance).await?
            }
            FileUploadFlowStep::MarkFileActive => {
                self.0.handler.handle_mark_file_active(instance).await?
            }
            FileUploadFlowStep::UpdateQuota => {
                self.0.handler.handle_update_quota(instance).await?
            }
            FileUploadFlowStep::UpdateBucketStats => {
                self.0.handler.handle_update_bucket_stats(instance).await?
            }
            FileUploadFlowStep::EmitUploadedEvent => {
                self.0.handler.handle_emit_uploaded_event(instance).await?
            }
            FileUploadFlowStep::Complete => {
                self.0.handler.handle_complete(instance).await?;
                None // Terminal step
            }
            FileUploadFlowStep::QuarantineFile => {
                self.0.handler.handle_quarantine_file(instance).await?
            }
            FileUploadFlowStep::EmitThreatEvent => {
                self.0.handler.handle_emit_threat_event(instance).await?
            }
            FileUploadFlowStep::NotifyThreat => {
                self.0.handler.handle_notify_threat(instance).await?
            }
            FileUploadFlowStep::CompleteQuarantine => {
                self.0.handler.handle_complete_quarantine(instance).await?;
                None // Terminal step
            }
            FileUploadFlowStep::BucketNotFound => {
                self.0.handler.handle_bucket_not_found(instance).await?;
                None // Terminal step
            }
            FileUploadFlowStep::BucketNotActive => {
                self.0.handler.handle_bucket_not_active(instance).await?;
                None // Terminal step
            }
            FileUploadFlowStep::MimeTypeNotAllowed => {
                self.0.handler.handle_mime_type_not_allowed(instance).await?;
                None // Terminal step
            }
            FileUploadFlowStep::FileTooLarge => {
                self.0.handler.handle_file_too_large(instance).await?;
                None // Terminal step
            }
            FileUploadFlowStep::QuotaExceeded => {
                self.0.handler.handle_quota_exceeded(instance).await?
            }
            FileUploadFlowStep::QuotaExceededTerminal => {
                self.0.handler.handle_quota_exceeded_terminal(instance).await?;
                None // Terminal step
            }
            FileUploadFlowStep::RollbackFileRecord => {
                self.0.handler.handle_rollback_file_record(instance).await?
            }
            FileUploadFlowStep::StorageFailed => {
                self.0.handler.handle_storage_failed(instance).await?;
                None // Terminal step
            }
        };

        // Mark current step as completed
        instance.completed_steps.push(current_step);

        // Move to next step
        match next_step {
            Some(next) => {
                instance.current_step = Some(next);
            }
            None => {
                instance.current_step = None;
                instance.status = FlowStatus::Completed;
            }
        }

        instance.updated_at = chrono::Utc::now();
        Ok(())
    }

    /// Run the flow to completion
    pub async fn run(&self, instance: &mut FileUploadFlowInstance) -> Result<(), FlowError> {
        while !instance.is_complete() && instance.status != FlowStatus::Waiting {
            self.execute_step(instance).await?;
        }
        Ok(())
    }

    /// Cancel the flow
    pub fn cancel(&self, instance: &mut FileUploadFlowInstance) { self.0.cancel(instance) }

    /// Mark flow as failed
    pub fn fail(&self, instance: &mut FileUploadFlowInstance, error: impl Into<String>) { self.0.fail(instance, error) }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_flow_instance_creation() {
        let instance = FileUploadFlowInstance::new("test-1");
        assert_eq!(instance.id, "test-1");
        assert_eq!(instance.status, FlowStatus::Pending);
        assert!(!instance.is_complete());
    }

    #[test]
    fn test_flow_context() {
        let mut instance = FileUploadFlowInstance::new("test-2");
        instance.set_context("key", serde_json::json!("value"));
        let value = instance.get_context("key");
        assert_eq!(value, Some(&serde_json::json!("value")));
    }

    #[test]
    fn test_flow_status_transitions() {
        let mut instance = FileUploadFlowInstance::new("test-3");
        assert!(!instance.is_running());

        instance.status = FlowStatus::Running;
        assert!(instance.is_running());
        assert!(!instance.is_complete());

        instance.status = FlowStatus::Completed;
        assert!(instance.is_complete());
        assert!(!instance.is_running());
    }
}
